import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  Container,
  Paper,
  Typography,
  Box,
  Grid,
  Chip,
  Divider,
  Button,
  CircularProgress,
  Alert,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Snackbar,
  Tabs,
  Tab,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Tooltip,
  Collapse,
  TextField,
  Rating,
  Avatar,
  Card,
  CardContent,
  CardHeader,
  CardActions,
  Badge,
  Accordion,
  AccordionSummary,
  AccordionDetails,
  Stepper,
  Step,
  StepLabel,
  StepContent,
  Breadcrumbs,
  Link,
  Menu,
  MenuItem,
  ToggleButton,
  ToggleButtonGroup,
} from '@mui/material';
import {
  LocationOn as LocationIcon,
  Business as BusinessIcon,
  Work as WorkIcon,
  AccessTime as TimeIcon,
  Share as ShareIcon,
  Bookmark as BookmarkIcon,
  BookmarkBorder as BookmarkBorderIcon,
  Description as DescriptionIcon,
  School as SchoolIcon,
  People as PeopleIcon,
  AttachMoney as MoneyIcon,
  Facebook,
  Twitter,
  LinkedIn,
  WhatsApp,
  Email,
  ExpandMore as ExpandMoreIcon,
  ExpandLess as ExpandLessIcon,
  Star as StarIcon,
  StarBorder as StarBorderIcon,
  CalendarToday as CalendarIcon,
  Language as LanguageIcon,
  Security as SecurityIcon,
  Verified as VerifiedIcon,
  QuestionAnswer as QAIcon,
  Assessment as AssessmentIcon,
  Schedule as ScheduleIcon,
  TrendingUp as GrowthIcon,
  Home as HomeIcon,
  WorkOutline as WorkOutlineIcon,
  MoreVert as MoreVertIcon,
  ContentCopy as CopyIcon,
  Print as PrintIcon,
  Download as DownloadIcon,
  Favorite as FavoriteIcon,
  FavoriteBorder as FavoriteBorderIcon,
  Compare as CompareIcon,
  Timeline as TimelineIcon,
  EmojiEvents as AchievementIcon,
  School as EducationIcon,
  Public as PublicIcon,
  BusinessCenter as BusinessCenterIcon,
  Group as GroupIcon,
  TrendingUp as TrendingUpIcon,
  CheckCircle as CheckCircleIcon,
  Warning as WarningIcon,
  Info as InfoIcon,
} from '@mui/icons-material';
import axios from 'axios';
import JobApplicationForm from '../components/JobApplicationForm';

interface JobDetails {
  id: string;
  title: string;
  department: string;
  location: string;
  type: string;
  description: string;
  requirements: string[];
  skills: string[];
  experience: string;
  salary: string;
  benefits: string[];
  responsibilities: string[];
  qualifications: string[];
  status: string;
  createdAt: string;
  updatedAt: string;
  company: {
    name: string;
    logo: string;
    description: string;
    website: string;
    rating: number;
    reviews: number;
    employees: string;
    founded: string;
    industry: string;
    headquarters: string;
    mission: string;
    values: string[];
    culture: string;
  };
  similarJobs: Array<{
    id: string;
    title: string;
    department: string;
    location: string;
    type: string;
  }>;
  interviewProcess: Array<{
    stage: string;
    description: string;
    duration: string;
  }>;
  applicationStats: {
    totalApplications: number;
    last24Hours: number;
    averageResponseTime: string;
  };
  salaryRange: {
    min: number;
    max: number;
    currency: string;
  };
  perks: Array<{
    title: string;
    description: string;
    icon: string;
  }>;
  growthOpportunities: Array<{
    title: string;
    description: string;
  }>;
  teamInfo: {
    size: string;
    structure: string;
    culture: string;
  };
  applicationTips: Array<{
    title: string;
    description: string;
  }>;
  faqs: Array<{
    question: string;
    answer: string;
  }>;
}

interface TabPanelProps {
  children?: React.ReactNode;
  index: number;
  value: number;
}

function TabPanel(props: TabPanelProps) {
  const { children, value, index, ...other } = props;

  return (
    <div
      role="tabpanel"
      hidden={value !== index}
      id={`job-tabpanel-${index}`}
      aria-labelledby={`job-tab-${index}`}
      {...other}
    >
      {value === index && <Box sx={{ p: 3 }}>{children}</Box>}
    </div>
  );
}

const JobDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [job, setJob] = useState<JobDetails | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [showApplicationForm, setShowApplicationForm] = useState(false);
  const [showShareDialog, setShowShareDialog] = useState(false);
  const [isBookmarked, setIsBookmarked] = useState(false);
  const [tabValue, setTabValue] = useState(0);
  const [snackbar, setSnackbar] = useState({ open: false, message: '' });
  const [expandedSections, setExpandedSections] = useState<{ [key: string]: boolean }>({});
  const [showSimilarJobs, setShowSimilarJobs] = useState(true);
  const [showInterviewProcess, setShowInterviewProcess] = useState(true);
  const [showCompanyCulture, setShowCompanyCulture] = useState(true);
  const [showApplicationStats, setShowApplicationStats] = useState(true);
  const [activeStep, setActiveStep] = useState(0);
  const [showSalaryCalculator, setShowSalaryCalculator] = useState(false);
  const [showPerks, setShowPerks] = useState(true);
  const [showGrowthOpportunities, setShowGrowthOpportunities] = useState(true);
  const [showTeamInfo, setShowTeamInfo] = useState(true);
  const [showApplicationTips, setShowApplicationTips] = useState(true);
  const [showFAQs, setShowFAQs] = useState(true);
  const [anchorEl, setAnchorEl] = useState<null | HTMLElement>(null);
  const [viewMode, setViewMode] = useState<'detailed' | 'compact'>('detailed');

  useEffect(() => {
    const fetchJobDetails = async () => {
      try {
        const response = await axios.get(`/api/jobs/${id}`);
        setJob(response.data);
        // Check if job is bookmarked
        const bookmarks = JSON.parse(localStorage.getItem('bookmarkedJobs') || '[]');
        setIsBookmarked(bookmarks.includes(id));
      } catch (err) {
        setError('Failed to load job details. Please try again later.');
      } finally {
        setLoading(false);
      }
    };

    fetchJobDetails();
  }, [id]);

  const handleTabChange = (event: React.SyntheticEvent, newValue: number) => {
    setTabValue(newValue);
  };

  const handleShare = () => {
    setShowShareDialog(true);
  };

  const handleCloseShareDialog = () => {
    setShowShareDialog(false);
  };

  const handleBookmark = () => {
    const bookmarks = JSON.parse(localStorage.getItem('bookmarkedJobs') || '[]');
    if (isBookmarked) {
      const newBookmarks = bookmarks.filter((jobId: string) => jobId !== id);
      localStorage.setItem('bookmarkedJobs', JSON.stringify(newBookmarks));
      setIsBookmarked(false);
      setSnackbar({ open: true, message: 'Job removed from bookmarks' });
    } else {
      bookmarks.push(id);
      localStorage.setItem('bookmarkedJobs', JSON.stringify(bookmarks));
      setIsBookmarked(true);
      setSnackbar({ open: true, message: 'Job added to bookmarks' });
    }
  };

  const handleSectionToggle = (section: string) => {
    setExpandedSections(prev => ({
      ...prev,
      [section]: !prev[section]
    }));
  };

  const handleShareSocial = (platform: string) => {
    const jobUrl = window.location.href;
    const message = `Check out this ${job?.type} position at ${job?.company.name}: ${job?.title}\n\nLocation: ${job?.location}\n\nApply now: ${jobUrl}`;
    
    switch (platform) {
      case 'facebook':
        window.open(`https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(jobUrl)}&quote=${encodeURIComponent(message)}`, '_blank');
        break;
      case 'twitter':
        window.open(`https://twitter.com/intent/tweet?text=${encodeURIComponent(message)}&url=${encodeURIComponent(jobUrl)}&hashtags=jobs,hiring,careers`, '_blank');
        break;
      case 'linkedin':
        window.open(`https://www.linkedin.com/sharing/share-offsite/?url=${encodeURIComponent(jobUrl)}&title=${encodeURIComponent(job?.title || '')}&summary=${encodeURIComponent(message)}`, '_blank');
        break;
      case 'whatsapp':
        window.open(`https://wa.me/?text=${encodeURIComponent(message)}`, '_blank');
        break;
      case 'email':
        window.open(`mailto:?subject=${encodeURIComponent(job?.title || '')}&body=${encodeURIComponent(message)}`, '_blank');
        break;
    }
    handleCloseShareDialog();
  };

  const handleViewModeChange = (event: React.MouseEvent<HTMLElement>, newMode: 'detailed' | 'compact') => {
    if (newMode !== null) {
      setViewMode(newMode);
    }
  };

  const handleMenuClick = (event: React.MouseEvent<HTMLElement>) => {
    setAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  const handlePrint = () => {
    window.print();
    handleMenuClose();
  };

  const handleCopyLink = () => {
    navigator.clipboard.writeText(window.location.href);
    setSnackbar({ open: true, message: 'Link copied to clipboard' });
    handleMenuClose();
  };

  const handleDownloadPDF = () => {
    // Implement PDF download functionality
    setSnackbar({ open: true, message: 'PDF download started' });
    handleMenuClose();
  };

  const handleCompare = () => {
    // Implement job comparison functionality
    setSnackbar({ open: true, message: 'Job added to comparison' });
    handleMenuClose();
  };

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="80vh">
        <CircularProgress />
      </Box>
    );
  }

  if (error || !job) {
    return (
      <Container maxWidth="md" sx={{ py: 4 }}>
        <Alert severity="error">{error || 'Job not found'}</Alert>
      </Container>
    );
  }

  return (
    <Container maxWidth="lg" sx={{ py: 4 }}>
      {/* Breadcrumbs */}
      <Box mb={3}>
        <Breadcrumbs aria-label="breadcrumb">
          <Link
            component="button"
            variant="body1"
            onClick={() => navigate('/')}
            sx={{ display: 'flex', alignItems: 'center' }}
          >
            <HomeIcon sx={{ mr: 0.5 }} fontSize="inherit" />
            Home
          </Link>
          <Link
            component="button"
            variant="body1"
            onClick={() => navigate('/jobs')}
            sx={{ display: 'flex', alignItems: 'center' }}
          >
            <WorkOutlineIcon sx={{ mr: 0.5 }} fontSize="inherit" />
            Jobs
          </Link>
          <Typography color="text.primary">{job.title}</Typography>
        </Breadcrumbs>
      </Box>

      <Grid container spacing={4}>
        {/* Job Details Section */}
        <Grid item xs={12} md={8}>
          <Paper elevation={3} sx={{ p: 4, borderRadius: 2 }}>
            <Box display="flex" justifyContent="space-between" alignItems="center" mb={3}>
              <Box>
                <Typography variant="h4" component="h1">
                  {job.title}
                </Typography>
                <Typography variant="subtitle1" color="text.secondary">
                  {job.company.name}
                </Typography>
              </Box>
              <Box display="flex" gap={1}>
                <Tooltip title="Bookmark">
                  <IconButton onClick={handleBookmark}>
                    {isBookmarked ? <BookmarkIcon color="primary" /> : <BookmarkBorderIcon />}
                  </IconButton>
                </Tooltip>
                <Tooltip title="Share">
                  <IconButton onClick={handleShare}>
                    <ShareIcon />
                  </IconButton>
                </Tooltip>
              </Box>
            </Box>

            <Box display="flex" justifyContent="space-between" alignItems="center" mb={3}>
              <Tabs value={tabValue} onChange={handleTabChange}>
                <Tab label="Overview" />
                <Tab label="Requirements" />
                <Tab label="Company" />
                <Tab label="Interview Process" />
              </Tabs>
              <Box display="flex" gap={1}>
                <ToggleButtonGroup
                  value={viewMode}
                  exclusive
                  onChange={handleViewModeChange}
                  size="small"
                >
                  <ToggleButton value="detailed">
                    <Tooltip title="Detailed View">
                      <DescriptionIcon />
                    </Tooltip>
                  </ToggleButton>
                  <ToggleButton value="compact">
                    <Tooltip title="Compact View">
                      <WorkIcon />
                    </Tooltip>
                  </ToggleButton>
                </ToggleButtonGroup>
                <IconButton onClick={handleMenuClick}>
                  <MoreVertIcon />
                </IconButton>
                <Menu
                  anchorEl={anchorEl}
                  open={Boolean(anchorEl)}
                  onClose={handleMenuClose}
                >
                  <MenuItem onClick={handlePrint}>
                    <ListItemIcon>
                      <PrintIcon fontSize="small" />
                    </ListItemIcon>
                    Print
                  </MenuItem>
                  <MenuItem onClick={handleCopyLink}>
                    <ListItemIcon>
                      <CopyIcon fontSize="small" />
                    </ListItemIcon>
                    Copy Link
                  </MenuItem>
                  <MenuItem onClick={handleDownloadPDF}>
                    <ListItemIcon>
                      <DownloadIcon fontSize="small" />
                    </ListItemIcon>
                    Download PDF
                  </MenuItem>
                  <MenuItem onClick={handleCompare}>
                    <ListItemIcon>
                      <CompareIcon fontSize="small" />
                    </ListItemIcon>
                    Compare
                  </MenuItem>
                </Menu>
              </Box>
            </Box>

            <Box display="flex" gap={2} flexWrap="wrap" mb={3}>
              <Chip
                icon={<BusinessIcon />}
                label={job.department}
                variant="outlined"
              />
              <Chip
                icon={<LocationIcon />}
                label={job.location}
                variant="outlined"
              />
              <Chip
                icon={<WorkIcon />}
                label={job.type}
                variant="outlined"
              />
              <Chip
                icon={<TimeIcon />}
                label={job.experience}
                variant="outlined"
              />
              <Chip
                icon={<MoneyIcon />}
                label={job.salary}
                variant="outlined"
              />
            </Box>

            <TabPanel value={tabValue} index={0}>
              <Box mb={4}>
                <Typography variant="h6" gutterBottom>
                  Job Description
                </Typography>
                <Typography variant="body1" paragraph>
                  {job.description}
                </Typography>
              </Box>

              <Box mb={4}>
                <Typography variant="h6" gutterBottom>
                  Key Responsibilities
                </Typography>
                <List>
                  {job.responsibilities.map((responsibility, index) => (
                    <ListItem key={index}>
                      <ListItemIcon>
                        <DescriptionIcon color="primary" />
                      </ListItemIcon>
                      <ListItemText primary={responsibility} />
                    </ListItem>
                  ))}
                </List>
              </Box>

              <Box mb={4}>
                <Typography variant="h6" gutterBottom>
                  Benefits
                </Typography>
                <List>
                  {job.benefits.map((benefit, index) => (
                    <ListItem key={index}>
                      <ListItemIcon>
                        <PeopleIcon color="primary" />
                      </ListItemIcon>
                      <ListItemText primary={benefit} />
                    </ListItem>
                  ))}
                </List>
              </Box>

              <Box mb={4}>
                <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
                  <Typography variant="h6">Company Culture</Typography>
                  <IconButton onClick={() => handleSectionToggle('culture')}>
                    {expandedSections['culture'] ? <ExpandLessIcon /> : <ExpandMoreIcon />}
                  </IconButton>
                </Box>
                <Collapse in={expandedSections['culture']}>
                  <Card variant="outlined">
                    <CardContent>
                      <Typography variant="body1" paragraph>
                        {job.company.culture}
                      </Typography>
                      <Box mt={2}>
                        <Typography variant="subtitle1" gutterBottom>
                          Company Values
                        </Typography>
                        <List>
                          {job.company.values.map((value, index) => (
                            <ListItem key={index}>
                              <ListItemIcon>
                                <VerifiedIcon color="primary" />
                              </ListItemIcon>
                              <ListItemText primary={value} />
                            </ListItem>
                          ))}
                        </List>
                      </Box>
                    </CardContent>
                  </Card>
                </Collapse>
              </Box>
            </TabPanel>

            <TabPanel value={tabValue} index={1}>
              <Box mb={4}>
                <Typography variant="h6" gutterBottom>
                  Requirements
                </Typography>
                <List>
                  {job.requirements.map((requirement, index) => (
                    <ListItem key={index}>
                      <ListItemIcon>
                        <DescriptionIcon color="primary" />
                      </ListItemIcon>
                      <ListItemText primary={requirement} />
                    </ListItem>
                  ))}
                </List>
              </Box>

              <Box mb={4}>
                <Typography variant="h6" gutterBottom>
                  Required Skills
                </Typography>
                <Box display="flex" gap={1} flexWrap="wrap">
                  {job.skills.map((skill, index) => (
                    <Chip key={index} label={skill} />
                  ))}
                </Box>
              </Box>

              <Box>
                <Typography variant="h6" gutterBottom>
                  Qualifications
                </Typography>
                <List>
                  {job.qualifications.map((qualification, index) => (
                    <ListItem key={index}>
                      <ListItemIcon>
                        <SchoolIcon color="primary" />
                      </ListItemIcon>
                      <ListItemText primary={qualification} />
                    </ListItem>
                  ))}
                </List>
              </Box>
            </TabPanel>

            <TabPanel value={tabValue} index={2}>
              <Box display="flex" alignItems="center" mb={3}>
                <img
                  src={job.company.logo}
                  alt={job.company.name}
                  style={{ width: 100, height: 100, objectFit: 'contain', marginRight: 16 }}
                />
                <Box>
                  <Typography variant="h6">{job.company.name}</Typography>
                  <Button
                    variant="outlined"
                    size="small"
                    href={job.company.website}
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    Visit Website
                  </Button>
                </Box>
              </Box>
              <Typography variant="body1" paragraph>
                {job.company.description}
              </Typography>

              <Box mb={4}>
                <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
                  <Typography variant="h6">Company Mission</Typography>
                  <IconButton onClick={() => handleSectionToggle('mission')}>
                    {expandedSections['mission'] ? <ExpandLessIcon /> : <ExpandMoreIcon />}
                  </IconButton>
                </Box>
                <Collapse in={expandedSections['mission']}>
                  <Card variant="outlined">
                    <CardContent>
                      <Typography variant="body1" paragraph>
                        {job.company.mission}
                      </Typography>
                    </CardContent>
                  </Card>
                </Collapse>
              </Box>

              <Box mb={4}>
                <Typography variant="h6" gutterBottom>
                  Company Information
                </Typography>
                <Grid container spacing={2}>
                  <Grid item xs={12} sm={6}>
                    <List>
                      <ListItem>
                        <ListItemIcon>
                          <PeopleIcon color="primary" />
                        </ListItemIcon>
                        <ListItemText primary="Employees" secondary={job.company.employees} />
                      </ListItem>
                      <ListItem>
                        <ListItemIcon>
                          <CalendarIcon color="primary" />
                        </ListItemIcon>
                        <ListItemText primary="Founded" secondary={job.company.founded} />
                      </ListItem>
                      <ListItem>
                        <ListItemIcon>
                          <BusinessIcon color="primary" />
                        </ListItemIcon>
                        <ListItemText primary="Industry" secondary={job.company.industry} />
                      </ListItem>
                    </List>
                  </Grid>
                  <Grid item xs={12} sm={6}>
                    <List>
                      <ListItem>
                        <ListItemIcon>
                          <LocationIcon color="primary" />
                        </ListItemIcon>
                        <ListItemText primary="Headquarters" secondary={job.company.headquarters} />
                      </ListItem>
                      <ListItem>
                        <ListItemIcon>
                          <LanguageIcon color="primary" />
                        </ListItemIcon>
                        <ListItemText primary="Website" secondary={job.company.website} />
                      </ListItem>
                      <ListItem>
                        <ListItemIcon>
                          <StarIcon color="primary" />
                        </ListItemIcon>
                        <ListItemText 
                          primary="Rating" 
                          secondary={
                            <Box display="flex" alignItems="center">
                              <Rating value={job.company.rating} readOnly precision={0.5} />
                              <Typography variant="body2" color="text.secondary" sx={{ ml: 1 }}>
                                ({job.company.reviews} reviews)
                              </Typography>
                            </Box>
                          } 
                        />
                      </ListItem>
                    </List>
                  </Grid>
                </Grid>
              </Box>
            </TabPanel>

            <TabPanel value={tabValue} index={3}>
              <Box mb={4}>
                <Typography variant="h6" gutterBottom>
                  Interview Process
                </Typography>
                <List>
                  {job.interviewProcess.map((stage, index) => (
                    <ListItem key={index}>
                      <ListItemIcon>
                        <AssessmentIcon color="primary" />
                      </ListItemIcon>
                      <ListItemText
                        primary={stage.stage}
                        secondary={
                          <>
                            <Typography variant="body2" component="span">
                              {stage.description}
                            </Typography>
                            <Box display="flex" alignItems="center" mt={1}>
                              <ScheduleIcon fontSize="small" sx={{ mr: 1 }} />
                              <Typography variant="caption" color="text.secondary">
                                {stage.duration}
                              </Typography>
                            </Box>
                          </>
                        }
                      />
                    </ListItem>
                  ))}
                </List>
              </Box>

              <Box mb={4}>
                <Typography variant="h6" gutterBottom>
                  Application Statistics
                </Typography>
                <Grid container spacing={2}>
                  <Grid item xs={12} sm={4}>
                    <Card variant="outlined">
                      <CardContent>
                        <Typography variant="h4" color="primary">
                          {job.applicationStats.totalApplications}
                        </Typography>
                        <Typography variant="body2" color="text.secondary">
                          Total Applications
                        </Typography>
                      </CardContent>
                    </Card>
                  </Grid>
                  <Grid item xs={12} sm={4}>
                    <Card variant="outlined">
                      <CardContent>
                        <Typography variant="h4" color="primary">
                          {job.applicationStats.last24Hours}
                        </Typography>
                        <Typography variant="body2" color="text.secondary">
                          Last 24 Hours
                        </Typography>
                      </CardContent>
                    </Card>
                  </Grid>
                  <Grid item xs={12} sm={4}>
                    <Card variant="outlined">
                      <CardContent>
                        <Typography variant="h4" color="primary">
                          {job.applicationStats.averageResponseTime}
                        </Typography>
                        <Typography variant="body2" color="text.secondary">
                          Average Response Time
                        </Typography>
                      </CardContent>
                    </Card>
                  </Grid>
                </Grid>
              </Box>
            </TabPanel>

            {/* Salary Calculator */}
            <Box mb={4}>
              <Accordion expanded={showSalaryCalculator} onChange={() => setShowSalaryCalculator(!showSalaryCalculator)}>
                <AccordionSummary expandIcon={<ExpandMoreIcon />}>
                  <Box display="flex" alignItems="center" gap={2}>
                    <MoneyIcon color="primary" />
                    <Typography variant="h6">Salary Calculator</Typography>
                  </Box>
                </AccordionSummary>
                <AccordionDetails>
                  <Grid container spacing={2}>
                    <Grid item xs={12} sm={6}>
                      <Typography variant="subtitle1" gutterBottom>
                        Base Salary Range
                      </Typography>
                      <Typography variant="body1">
                        {job.salaryRange.currency} {job.salaryRange.min.toLocaleString()} - {job.salaryRange.max.toLocaleString()}
                      </Typography>
                    </Grid>
                    <Grid item xs={12} sm={6}>
                      <Typography variant="subtitle1" gutterBottom>
                        Estimated Annual Compensation
                      </Typography>
                      <Typography variant="body1">
                        {job.salaryRange.currency} {(job.salaryRange.min * 1.2).toLocaleString()} - {(job.salaryRange.max * 1.2).toLocaleString()}
                      </Typography>
                    </Grid>
                  </Grid>
                </AccordionDetails>
              </Accordion>
            </Box>

            {/* Perks & Benefits */}
            <Box mb={4}>
              <Accordion expanded={showPerks} onChange={() => setShowPerks(!showPerks)}>
                <AccordionSummary expandIcon={<ExpandMoreIcon />}>
                  <Box display="flex" alignItems="center" gap={2}>
                    <FavoriteIcon color="primary" />
                    <Typography variant="h6">Perks & Benefits</Typography>
                  </Box>
                </AccordionSummary>
                <AccordionDetails>
                  <Grid container spacing={2}>
                    {job.perks.map((perk, index) => (
                      <Grid item xs={12} sm={6} key={index}>
                        <Card variant="outlined">
                          <CardContent>
                            <Box display="flex" alignItems="center" gap={2} mb={2}>
                              <Avatar sx={{ bgcolor: 'primary.main' }}>
                                {perk.icon}
                              </Avatar>
                              <Typography variant="h6">{perk.title}</Typography>
                            </Box>
                            <Typography variant="body2">{perk.description}</Typography>
                          </CardContent>
                        </Card>
                      </Grid>
                    ))}
                  </Grid>
                </AccordionDetails>
              </Accordion>
            </Box>

            {/* Growth Opportunities */}
            <Box mb={4}>
              <Accordion expanded={showGrowthOpportunities} onChange={() => setShowGrowthOpportunities(!showGrowthOpportunities)}>
                <AccordionSummary expandIcon={<ExpandMoreIcon />}>
                  <Box display="flex" alignItems="center" gap={2}>
                    <TrendingUpIcon color="primary" />
                    <Typography variant="h6">Growth Opportunities</Typography>
                  </Box>
                </AccordionSummary>
                <AccordionDetails>
                  <Stepper orientation="vertical">
                    {job.growthOpportunities.map((opportunity, index) => (
                      <Step key={index} active={index <= activeStep}>
                        <StepLabel>{opportunity.title}</StepLabel>
                        <StepContent>
                          <Typography variant="body2">{opportunity.description}</Typography>
                        </StepContent>
                      </Step>
                    ))}
                  </Stepper>
                </AccordionDetails>
              </Accordion>
            </Box>

            {/* Team Information */}
            <Box mb={4}>
              <Accordion expanded={showTeamInfo} onChange={() => setShowTeamInfo(!showTeamInfo)}>
                <AccordionSummary expandIcon={<ExpandMoreIcon />}>
                  <Box display="flex" alignItems="center" gap={2}>
                    <GroupIcon color="primary" />
                    <Typography variant="h6">Team Information</Typography>
                  </Box>
                </AccordionSummary>
                <AccordionDetails>
                  <Grid container spacing={2}>
                    <Grid item xs={12} sm={4}>
                      <Card variant="outlined">
                        <CardContent>
                          <Typography variant="subtitle1" gutterBottom>
                            Team Size
                          </Typography>
                          <Typography variant="body1">{job.teamInfo.size}</Typography>
                        </CardContent>
                      </Card>
                    </Grid>
                    <Grid item xs={12} sm={4}>
                      <Card variant="outlined">
                        <CardContent>
                          <Typography variant="subtitle1" gutterBottom>
                            Team Structure
                          </Typography>
                          <Typography variant="body1">{job.teamInfo.structure}</Typography>
                        </CardContent>
                      </Card>
                    </Grid>
                    <Grid item xs={12} sm={4}>
                      <Card variant="outlined">
                        <CardContent>
                          <Typography variant="subtitle1" gutterBottom>
                            Team Culture
                          </Typography>
                          <Typography variant="body1">{job.teamInfo.culture}</Typography>
                        </CardContent>
                      </Card>
                    </Grid>
                  </Grid>
                </AccordionDetails>
              </Accordion>
            </Box>

            {/* Application Tips */}
            <Box mb={4}>
              <Accordion expanded={showApplicationTips} onChange={() => setShowApplicationTips(!showApplicationTips)}>
                <AccordionSummary expandIcon={<ExpandMoreIcon />}>
                  <Box display="flex" alignItems="center" gap={2}>
                    <CheckCircleIcon color="primary" />
                    <Typography variant="h6">Application Tips</Typography>
                  </Box>
                </AccordionSummary>
                <AccordionDetails>
                  <List>
                    {job.applicationTips.map((tip, index) => (
                      <ListItem key={index}>
                        <ListItemIcon>
                          <InfoIcon color="primary" />
                        </ListItemIcon>
                        <ListItemText
                          primary={tip.title}
                          secondary={tip.description}
                        />
                      </ListItem>
                    ))}
                  </List>
                </AccordionDetails>
              </Accordion>
            </Box>

            {/* FAQs */}
            <Box mb={4}>
              <Accordion expanded={showFAQs} onChange={() => setShowFAQs(!showFAQs)}>
                <AccordionSummary expandIcon={<ExpandMoreIcon />}>
                  <Box display="flex" alignItems="center" gap={2}>
                    <QAIcon color="primary" />
                    <Typography variant="h6">Frequently Asked Questions</Typography>
                  </Box>
                </AccordionSummary>
                <AccordionDetails>
                  <List>
                    {job.faqs.map((faq, index) => (
                      <ListItem key={index}>
                        <ListItemText
                          primary={
                            <Typography variant="subtitle1" color="primary">
                              {faq.question}
                            </Typography>
                          }
                          secondary={faq.answer}
                        />
                      </ListItem>
                    ))}
                  </List>
                </AccordionDetails>
              </Accordion>
            </Box>
          </Paper>

          {/* Similar Jobs Section */}
          <Box mt={4}>
            <Paper elevation={3} sx={{ p: 4, borderRadius: 2 }}>
              <Box display="flex" justifyContent="space-between" alignItems="center" mb={3}>
                <Typography variant="h6">Similar Jobs</Typography>
                <IconButton onClick={() => setShowSimilarJobs(!showSimilarJobs)}>
                  {showSimilarJobs ? <ExpandLessIcon /> : <ExpandMoreIcon />}
                </IconButton>
              </Box>
              <Collapse in={showSimilarJobs}>
                <Grid container spacing={2}>
                  {job.similarJobs.map((similarJob) => (
                    <Grid item xs={12} sm={6} key={similarJob.id}>
                      <Card variant="outlined">
                        <CardContent>
                          <Typography variant="h6" gutterBottom>
                            {similarJob.title}
                          </Typography>
                          <Box display="flex" gap={1} flexWrap="wrap" mb={2}>
                            <Chip size="small" label={similarJob.department} />
                            <Chip size="small" label={similarJob.location} />
                            <Chip size="small" label={similarJob.type} />
                          </Box>
                          <Button
                            variant="outlined"
                            size="small"
                            onClick={() => navigate(`/jobs/${similarJob.id}`)}
                          >
                            View Details
                          </Button>
                        </CardContent>
                      </Card>
                    </Grid>
                  ))}
                </Grid>
              </Collapse>
            </Paper>
          </Box>
        </Grid>

        {/* Application Section */}
        <Grid item xs={12} md={4}>
          <Paper elevation={3} sx={{ p: 4, borderRadius: 2, position: 'sticky', top: 20 }}>
            {showApplicationForm ? (
              <JobApplicationForm />
            ) : (
              <Box textAlign="center">
                <Typography variant="h6" gutterBottom>
                  Interested in this position?
                </Typography>
                <Typography variant="body1" color="text.secondary" paragraph>
                  Submit your application and our AI will review your qualifications.
                </Typography>
                <Button
                  variant="contained"
                  size="large"
                  fullWidth
                  onClick={() => setShowApplicationForm(true)}
                  sx={{ mb: 2 }}
                >
                  Apply Now
                </Button>
                <Box mb={2}>
                  <Typography variant="body2" color="text.secondary">
                    Posted on {new Date(job.createdAt).toLocaleDateString()}
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    Last updated: {new Date(job.updatedAt).toLocaleDateString()}
                  </Typography>
                </Box>
                <Box display="flex" justifyContent="center" gap={1}>
                  <Tooltip title="Save for later">
                    <IconButton onClick={handleBookmark}>
                      {isBookmarked ? <BookmarkIcon color="primary" /> : <BookmarkBorderIcon />}
                    </IconButton>
                  </Tooltip>
                  <Tooltip title="Share this job">
                    <IconButton onClick={handleShare}>
                      <ShareIcon />
                    </IconButton>
                  </Tooltip>
                </Box>
              </Box>
            )}
          </Paper>
        </Grid>
      </Grid>

      {/* Share Dialog */}
      <Dialog open={showShareDialog} onClose={handleCloseShareDialog}>
        <DialogTitle>Share this job</DialogTitle>
        <DialogContent>
          <Box display="flex" justifyContent="center" gap={2} mt={2}>
            <IconButton onClick={() => handleShareSocial('facebook')} color="primary">
              <Facebook fontSize="large" />
            </IconButton>
            <IconButton onClick={() => handleShareSocial('twitter')} color="primary">
              <Twitter fontSize="large" />
            </IconButton>
            <IconButton onClick={() => handleShareSocial('linkedin')} color="primary">
              <LinkedIn fontSize="large" />
            </IconButton>
            <IconButton onClick={() => handleShareSocial('whatsapp')} color="primary">
              <WhatsApp fontSize="large" />
            </IconButton>
            <IconButton onClick={() => handleShareSocial('email')} color="primary">
              <Email fontSize="large" />
            </IconButton>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleCloseShareDialog}>Close</Button>
        </DialogActions>
      </Dialog>

      {/* Snackbar for notifications */}
      <Snackbar
        open={snackbar.open}
        autoHideDuration={3000}
        onClose={() => setSnackbar({ ...snackbar, open: false })}
        message={snackbar.message}
      />
    </Container>
  );
};

export default JobDetails;
